/**
 * Lightweight Sentry Error Tracker for Chrome Extension
 * Sends errors directly to Sentry API without full SDK
 */

window.Sentry = {
  init: function(config) {
    this.dsn = config.dsn;
    this.environment = config.environment || 'production';
    this.release = config.release || 'unknown';
    this.beforeSend = config.beforeSend;
    console.log('[Sentry] Initialized:', this.environment);
  },

  captureException: function(error, context) {
    if (!this.dsn) return;

    const event = {
      exception: {
        values: [{
          type: error.name || 'Error',
          value: error.message || String(error),
          stacktrace: {
            frames: this._parseStackTrace(error.stack)
          }
        }]
      },
      level: 'error',
      environment: this.environment,
      release: this.release,
      timestamp: Date.now() / 1000,
      platform: 'javascript',
      tags: context?.tags || {},
      extra: context?.extra || {}
    };

    if (this.beforeSend) {
      const modifiedEvent = this.beforeSend(event);
      if (!modifiedEvent) return; // Event was dropped
      this._send(modifiedEvent);
    } else {
      this._send(event);
    }
  },

  captureMessage: function(message, level) {
    if (!this.dsn) return;

    const event = {
      message: {
        message: message
      },
      level: level || 'info',
      environment: this.environment,
      release: this.release,
      timestamp: Date.now() / 1000,
      platform: 'javascript'
    };

    if (this.beforeSend) {
      const modifiedEvent = this.beforeSend(event);
      if (!modifiedEvent) return;
      this._send(modifiedEvent);
    } else {
      this._send(event);
    }
  },

  _parseStackTrace: function(stack) {
    if (!stack) return [];

    return stack.split('\n').slice(1).map(line => {
      const match = line.match(/at\s+(.*?)\s+\((.*?):(\d+):(\d+)\)/) ||
                    line.match(/at\s+(.*?):(\d+):(\d+)/);

      if (!match) return { filename: 'unknown', function: 'unknown', lineno: 0, colno: 0 };

      return {
        filename: match[2] || match[1],
        function: match[1] || 'anonymous',
        lineno: parseInt(match[3] || match[2], 10),
        colno: parseInt(match[4] || match[3], 10)
      };
    }).filter(frame => frame.filename !== 'unknown');
  },

  _send: function(event) {
    // Parse DSN to get the endpoint
    const dsnMatch = this.dsn.match(/https:\/\/(.+)@(.+)\/(\d+)/);
    if (!dsnMatch) {
      console.error('[Sentry] Invalid DSN format');
      return;
    }

    const [_, publicKey, host, projectId] = dsnMatch;
    const endpoint = `https://${host}/api/${projectId}/store/`;

    const headers = {
      'Content-Type': 'application/json',
      'X-Sentry-Auth': `Sentry sentry_version=7, sentry_key=${publicKey}, sentry_client=custom-extension/1.0.0`
    };

    // Send via fetch
    fetch(endpoint, {
      method: 'POST',
      headers: headers,
      body: JSON.stringify(event)
    }).then(() => {
      console.log('[Sentry] Error reported');
    }).catch(err => {
      console.warn('[Sentry] Failed to send error:', err.message);
    });
  },

  // Stub for compatibility
  browserTracingIntegration: function() { return {}; }
};
